import { __ } from "@wordpress/i18n";
import {
	InspectorControls,
	MediaUpload,
	MediaUploadCheck,
	useBlockProps,
	useSettings,
} from "@wordpress/block-editor";
import {
	__experimentalUnitControl,
	BaseControl,
	Button,
	ColorPalette,
	PanelBody,
	SelectControl,
	ToggleControl,
} from "@wordpress/components";
import "./editor.scss";

export default function Edit({ attributes, setAttributes }) {
	const [colors] = useSettings("color.palette");
	const images = attributes.images.map((image) => (
		<li key={image.id} className="wp-block-create-block-running-images__list">
			<img
				className="wp-block-create-block-running-images__img"
				src={image.url}
				alt={image.alt}
			/>
		</li>
	));
	const blockProps = useBlockProps({
		className: attributes.imageObjectFit ? "is-image-contained" : "",
		style: {
			"--animation-duration": attributes.animationDuration,
			"--aspect-ratio": attributes.imageAspectRatio,
			"--border-image-color": attributes.imageBorderColor,
			"--border-image-width": attributes.imageBorderWidth,
			"--border-image-radius": attributes.imageBorderRadius,
			"--column-gap": attributes.columnGap,
			"--max-height": attributes.imageMaxHeight,
			"--image-padding-block": attributes.imagePaddingBlock,
			"--image-padding-inline": attributes.imagePaddingInline,
		},
	});
	return (
		<>
			<InspectorControls>
				<PanelBody title={__("Settings", "running-images")}>
					<BaseControl label={__("Please set your images", "running-images")}>
						<MediaUpload
							title={__("Select Images", "running-images")}
							allowedTypes={["image"]}
							multiple="add"
							gallery={true}
							addToGallery={true}
							value={attributes.images.map(({ id }) => id)}
							onSelect={(images) =>
								setAttributes({
									images: images.map((image) => ({
										id: image.id,
										url: image.url,
										alt: image.alt,
									})),
								})
							}
							render={({ open }) =>
								<Button variant="secondary" onClick={open}>
									Set Images
								</Button>
							}
						/>
					</BaseControl>
					<SelectControl
						label={__("Image Aspect Ratio", "running-images")}
						value={attributes.imageAspectRatio}
						options={[
							{ label: "Landscape (16:9)", value: "16/9" },
							{ label: "Landscape (3:2)", value: "3/2" },
							{ label: "Landscape (4:3)", value: "4/3" },
							{ label: "Square", value: "1/1" },
							{ label: "Portrait (3:4)", value: "3/4" },
							{ label: "Portrait (2:3)", value: "2/3" },
							{ label: "Portrait (9:16)", value: "9/16" },
						]}
						onChange={(value) => setAttributes({ imageAspectRatio: value })}
					/>
					<BaseControl label={__("Object Fit", "running-images")}>
						<ToggleControl
							label={__("Contain")}
							help={
								attributes.imageObjectFit
									? "The images will be displayed inside the space"
									: "The images will be displayed covering all of the space"
							}
							checked={attributes.imageObjectFit}
							onChange={(imageObjectFit) => {
								setAttributes({ imageObjectFit });
							}}
						/>
					</BaseControl>
					<__experimentalUnitControl
						label={__("Image Max Height", "running-images")}
						value={attributes.imageMaxHeight}
						onChange={(value) => setAttributes({ imageMaxHeight: value })}
					/>
					<__experimentalUnitControl
						label={__("Image Border Width", "running-images")}
						value={attributes.imageBorderWidth}
						onChange={(value) => setAttributes({ imageBorderWidth: value })}
					/>
					<BaseControl label={__("Image Border Color", "running-images")}>
						<ColorPalette
							colors={colors}
							value={attributes.imageBorderColor}
							onChange={(color) => setAttributes({ imageBorderColor: color })}
						/>
					</BaseControl>
					<__experimentalUnitControl
						label={__("Image Border Radius", "running-images")}
						value={attributes.imageBorderRadius}
						onChange={(value) => setAttributes({ imageBorderRadius: value })}
					/>
					<__experimentalUnitControl
						label={__("Image Padding Block", "running-images")}
						value={attributes.imagePaddingBlock}
						onChange={(value) => setAttributes({ imagePaddingBlock: value })}
					/>
					<__experimentalUnitControl
						label={__("Image Padding Inline", "running-images")}
						value={attributes.imagePaddingInline}
						onChange={(value) => setAttributes({ imagePaddingInline: value })}
					/>
					<__experimentalUnitControl
						label={__("Image Gap", "running-images")}
						value={attributes.columnGap}
						onChange={(value) => setAttributes({ columnGap: value })}
					/>
					<__experimentalUnitControl
						label={__("Animation Duration", "running-images")}
						value={attributes.animationDuration}
						onChange={(value) => setAttributes({ animationDuration: value })}
						units={[
							{ value: "ms", label: "ms" },
							{ value: "s", label: "s" },
						]}
					/>
				</PanelBody>
			</InspectorControls>
			{attributes.images.length === 0 ? (
				<div {...blockProps}>
					<p>Please select your images.</p>
				</div>
			) : (
				<div {...blockProps}>
					<div className="wp-block-create-block-running-images__track">
						{images}
					</div>
					<div className="wp-block-create-block-running-images__track">
						{images}
					</div>
				</div>
			)}
		</>
	);
}
